1	import { writable, derived } from 'svelte/store';
2	import type { NewQuestionInput, Question, QuestionPatch } from '@domain/questions/question';
3	import {
4	  validateQuestion, applyPatch, copy as copyQuestion, deactivate, activate, softDelete, restore
5	} from '@domain/questions/questionRules';
6	import { questionsRepository } from '@persistence/questionsRepository';
7	import { businessConfig } from './businessConfig';
8	import { uid } from '@shared/utils/id';
9	import { requireRole, requireSession } from './authorization';
10	
11	const questionsStore = writable<Question[]>([]);
12	const showDeletedStore = writable<boolean>(false);
13	
14	export const questions = { subscribe: questionsStore.subscribe };
15	export const showDeleted = {
16	  subscribe: showDeletedStore.subscribe,
17	  toggle: () => showDeletedStore.update((v) => !v),
18	  set: (v: boolean) => showDeletedStore.set(v)
19	};
20	
21	export const visibleQuestions = derived(
22	  [questionsStore, showDeletedStore],
23	  ([$q, $show]) => $show ? $q : $q.filter((q) => q.status !== 'deleted')
24	);
25	
26	/**
27	 * Question reads require an active session — anonymous callers cannot scrape
28	 * the question bank by invoking the service directly.
29	 */
30	export async function refreshQuestions(): Promise<void> {
31	  requireSession();
32	  questionsStore.set(await questionsRepository.list());
33	}
34	
35	function limits() {
36	  return businessConfig().questions;
37	}
38	
39	export async function createQuestion(input: NewQuestionInput): Promise<{ ok: true; question: Question } | { ok: false; errors: string[] }> {
40	  requireRole('content_author', 'administrator');
41	  const v = validateQuestion(input, limits());
42	  if (!v.ok) return v;
43	  const now = Date.now();
44	  const q: Question = { ...input, id: uid('q'), status: 'active', createdAt: now, updatedAt: now, deletedAt: null };
45	  await questionsRepository.put(q);
46	  await refreshQuestions();
47	  return { ok: true, question: q };
48	}
49	
50	export async function editQuestion(id: string, patch: QuestionPatch): Promise<{ ok: true; question: Question } | { ok: false; errors: string[] }> {
51	  requireRole('content_author', 'administrator');
52	  const existing = await questionsRepository.get(id);
53	  if (!existing) return { ok: false, errors: ['Not found'] };
54	  const merged = { ...existing, ...patch } as NewQuestionInput;
55	  const v = validateQuestion(merged, limits());
56	  if (!v.ok) return v;
57	  const updated = applyPatch(existing, patch);
58	  await questionsRepository.put(updated);
59	  await refreshQuestions();
60	  return { ok: true, question: updated };
61	}
62	
63	export async function copyQuestionById(id: string): Promise<Question | null> {
64	  requireRole('content_author', 'administrator');
65	  const existing = await questionsRepository.get(id);
66	  if (!existing) return null;
67	  const cloned = copyQuestion(existing, uid('q'));
68	  await questionsRepository.put(cloned);
69	  await refreshQuestions();
70	  return cloned;
71	}
72	
73	export async function setActive(id: string, active: boolean): Promise<void> {
74	  requireRole('content_author', 'administrator');
75	  const existing = await questionsRepository.get(id);
76	  if (!existing) return;
77	  const updated = active ? activate(existing) : deactivate(existing);
78	  await questionsRepository.put(updated);
79	  await refreshQuestions();
80	}
81	
82	export async function softDeleteQuestion(id: string): Promise<void> {
83	  requireRole('content_author', 'administrator');
84	  const existing = await questionsRepository.get(id);
85	  if (!existing) return;
86	  await questionsRepository.put(softDelete(existing));
87	  await refreshQuestions();
88	}
89	
90	export async function restoreQuestion(id: string): Promise<void> {
91	  requireRole('content_author', 'administrator');
92	  const existing = await questionsRepository.get(id);
93	  if (!existing) return;
94	  await questionsRepository.put(restore(existing));
95	  await refreshQuestions();
96	}
