1	import type { Role } from '@domain/auth/role';
2	import { currentRole, currentUserId } from './authService';
3	import { logger } from '@shared/logging/logger';
4	
5	export class AuthorizationError extends Error {
6	  constructor(message = 'Forbidden') {
7	    super(message);
8	    this.name = 'AuthorizationError';
9	  }
10	}
11	
12	/** Resolve the active session's user id or throw. */
13	export function requireSession(): string {
14	  const id = currentUserId();
15	  if (!id) {
16	    logger.warn('auth.denied', { reason: 'no_session' });
17	    throw new AuthorizationError('Authentication required');
18	  }
19	  return id;
20	}
21	
22	/** Resolve the active session and verify the role is allowed, or throw. */
23	export function requireRole(...allowed: Role[]): { userId: string; role: Role } {
24	  const userId = requireSession();
25	  const role = currentRole();
26	  if (!role || !allowed.includes(role)) {
27	    logger.warn('auth.denied', { reason: 'wrong_role', userId, role, required: allowed });
28	    throw new AuthorizationError(`Role '${role ?? 'anonymous'}' is not authorized`);
29	  }
30	  return { userId, role };
31	}
32	
33	/** True if the active session's role is one of the supplied roles. */
34	export function hasAnyRole(...allowed: Role[]): boolean {
35	  const role = currentRole();
36	  return role !== null && allowed.includes(role);
37	}
