1	import {
2	  requiresSecondReview, roundToIncrement, applyTypeWeight
3	} from '@domain/grading/scoring';
4	import { encryptString, decryptString, type EncryptedField } from '@shared/crypto/fieldCrypto';
5	import { gradesRepository, DuplicateGradeError, type Grade } from '@persistence/gradesRepository';
6	import { attemptsRepository } from '@persistence/attemptsRepository';
7	import { questionsRepository } from '@persistence/questionsRepository';
8	import { businessConfig } from './businessConfig';
9	import { currentEncryptionKey } from './authService';
10	import { requireRole, requireSession } from './authorization';
11	import { uid } from '@shared/utils/id';
12	import { logger } from '@shared/logging/logger';
13	
14	export interface ManualGradeInput {
15	  attemptId: string;
16	  score: number;
17	  notes: string;
18	}
19	
20	export interface SecondReviewInput {
21	  score: number;
22	  notes: string;
23	}
24	
25	/** Raised when the active session cannot decrypt a notes payload (typically because it was written by a different reviewer). */
26	export class NotesDecryptionError extends Error {
27	  constructor() {
28	    super('Notes are encrypted with a different reviewer\'s key and cannot be decrypted in this session');
29	    this.name = 'NotesDecryptionError';
30	  }
31	}
32	
33	async function encryptNotes(notes: string): Promise<EncryptedField | null> {
34	  if (!notes) return null;
35	  const key = currentEncryptionKey();
36	  if (!key) throw new Error('No encryption key in session');
37	  return encryptString(key, notes);
38	}
39	
40	export async function decryptNotes(payload: EncryptedField | null): Promise<string> {
41	  if (!payload) return '';
42	  const key = currentEncryptionKey();
43	  if (!key) throw new NotesDecryptionError();
44	  try {
45	    return await decryptString(key, payload);
46	  } catch {
47	    // Wrong key (cross-user notes), corrupt payload, or any other AES failure.
48	    throw new NotesDecryptionError();
49	  }
50	}
51	
52	function gradingKnobs() {
53	  const cfg = businessConfig().grading;
54	  return {
55	    increment: cfg.partialIncrement,
56	    weights: cfg.weights,
57	    deltaThreshold: cfg.secondReviewDelta
58	  };
59	}
60	
61	/**
62	 * Read-only helper that lets the review UI (and the duplicate-guard inside
63	 * `submitFirstReview`) check whether any grader has already submitted a
64	 * grade for the given attempt — globally, not filtered by current grader.
65	 */
66	export async function findGradeByAttempt(attemptId: string): Promise<Grade | null> {
67	  requireSession();
68	  return (await gradesRepository.findByAttemptId(attemptId)) ?? null;
69	}
70	
71	/**
72	 * First review submission. Enforces the one-grade-per-attempt invariant at
73	 * the service boundary by explicitly probing the global index, and is
74	 * defended in depth by the unique IDB index on `attemptId` which surfaces
75	 * as `DuplicateGradeError` for any race that slipped past the probe.
76	 *
77	 * The grade is COMPLETED with the type-weighted first score; a second
78	 * review is optional.
79	 */
80	export async function submitFirstReview(input: ManualGradeInput): Promise<Grade> {
81	  const { userId: grader } = requireRole('reviewer', 'administrator');
82	  const attempt = await attemptsRepository.get(input.attemptId);
83	  if (!attempt) throw new Error('Attempt not found');
84	  const question = await questionsRepository.get(attempt.questionId);
85	  if (!question) throw new Error('Question not found');
86	  if (!Number.isFinite(input.score) || input.score < 0 || input.score > question.maxScore) {
87	    throw new Error(`Score must be between 0 and ${question.maxScore}`);
88	  }
89	  // Service-level uniqueness probe.
90	  const existing = await gradesRepository.findByAttemptId(input.attemptId);
91	  if (existing) {
92	    logger.warn('grading.first.duplicate', { attemptId: input.attemptId, existingGradeId: existing.id, grader });
93	    throw new Error('A grade already exists for this attempt');
94	  }
95	
96	  const knobs = gradingKnobs();
97	  const rounded = roundToIncrement(input.score, knobs.increment);
98	  const weighted = applyTypeWeight(rounded, question.type, knobs.weights, knobs.increment);
99	  const notesEncrypted = await encryptNotes(input.notes);
100	
101	  const now = Date.now();
102	  const grade: Grade = {
103	    id: uid('grade'),
104	    attemptId: attempt.id,
105	    questionId: question.id,
106	    graderId: grader,
107	    firstScore: rounded,
108	    secondScore: null,
109	    secondGraderId: null,
110	    finalScore: weighted,
111	    awaitingSecondReview: false,
112	    blockedReason: null,
113	    notesEncrypted,
114	    createdAt: now,
115	    updatedAt: now
116	  };
117	  try {
118	    await gradesRepository.put(grade);
119	  } catch (e) {
120	    if (e instanceof DuplicateGradeError) {
121	      logger.warn('grading.first.race', { attemptId: input.attemptId, grader });
122	      throw new Error('A grade already exists for this attempt');
123	    }
124	    throw e;
125	  }
126	  logger.info('grading.first', {
127	    gradeId: grade.id, attemptId: attempt.id, graderId: grader,
128	    questionType: question.type, firstScore: rounded, finalScore: weighted
129	  });
130	  return grade;
131	}
132	
133	/**
134	 * Second review submission. ALWAYS finalizes the grade as the type-weighted
135	 * average of the two reviewers, regardless of delta. A delta exceeding the
136	 * configured threshold is logged for audit but does NOT require any third
137	 * confirmation step — the second review is, by itself, the resolution.
138	 */
139	export async function submitSecondReview(gradeId: string, input: SecondReviewInput): Promise<Grade> {
140	  const { userId: grader } = requireRole('reviewer', 'administrator');
141	  const grade = await gradesRepository.get(gradeId);
142	  if (!grade) throw new Error('Grade not found');
143	  const question = await questionsRepository.get(grade.questionId);
144	  if (!question) throw new Error('Question not found');
145	  if (!Number.isFinite(input.score) || input.score < 0 || input.score > question.maxScore) {
146	    throw new Error(`Score must be between 0 and ${question.maxScore}`);
147	  }
148	  if (grader === grade.graderId) throw new Error('Second review must be by a different grader');
149	
150	  const knobs = gradingKnobs();
151	  const rounded = roundToIncrement(input.score, knobs.increment);
152	  const notesEncrypted = await encryptNotes(input.notes);
153	  const exceedsThreshold = requiresSecondReview(grade.firstScore, rounded, knobs.deltaThreshold);
154	
155	  if (exceedsThreshold) {
156	    logger.warn('grading.delta.exceeded', {
157	      gradeId, attemptId: grade.attemptId,
158	      firstScore: grade.firstScore, secondScore: rounded,
159	      delta: Math.abs(grade.firstScore - rounded), threshold: knobs.deltaThreshold
160	    });
161	  }
162	
163	  const avg = (grade.firstScore + rounded) / 2;
164	  const weightedFinal = applyTypeWeight(avg, question.type, knobs.weights, knobs.increment);
165	  const updated: Grade = {
166	    ...grade,
167	    secondScore: rounded,
168	    secondGraderId: grader,
169	    finalScore: weightedFinal,
170	    awaitingSecondReview: false,
171	    blockedReason: exceedsThreshold
172	      ? `Audit: delta ${Math.abs(grade.firstScore - rounded)} exceeded threshold ${knobs.deltaThreshold}`
173	      : null,
174	    notesEncrypted: notesEncrypted ?? grade.notesEncrypted,
175	    updatedAt: Date.now()
176	  };
177	  await gradesRepository.put(updated);
178	  logger.info('grading.second', {
179	    gradeId, attemptId: grade.attemptId, secondGraderId: grader,
180	    secondScore: rounded, finalScore: weightedFinal,
181	    deltaExceeded: exceedsThreshold
182	  });
183	  return updated;
184	}
185	
186	/** A grade is complete once it carries a non-null final score. */
187	export function isComplete(grade: Grade): boolean {
188	  return grade.finalScore !== null;
189	}
190	
191	/**
192	 * Reviewers and administrators see every grade in the system so they can
193	 * make informed decisions before submitting their own first review (no
194	 * blind spots). Other roles get an empty list.
195	 */
196	export async function listGrades(): Promise<Grade[]> {
197	  requireRole('reviewer', 'administrator');
198	  return gradesRepository.list();
199	}
200	
