1	import type { ActivityLevel, DietaryPreferences } from './healthProfile';
2	
3	const ACTIVITY_FACTOR: Record<ActivityLevel, number> = {
4	  sedentary: 0.85,
5	  light: 0.95,
6	  moderate: 1.0,
7	  active: 1.1,
8	  very_active: 1.2
9	};
10	
11	export interface NutritionBudget {
12	  calories: number;       // kcal/day
13	  proteinGrams: number;   // g/day target
14	  sodiumMg: number;       // mg/day cap
15	  addedSugarGrams: number;// g/day cap
16	}
17	
18	/** Deterministic budget — same inputs always produce the same output. */
19	export function calculateNutritionBudget(prefs: DietaryPreferences): NutritionBudget | null {
20	  if (prefs.age === null || prefs.activityLevel === null) return null;
21	  if (!Number.isFinite(prefs.age) || prefs.age <= 0 || prefs.age > 120) return null;
22	
23	  const base = 2000;
24	  const ageDelta = prefs.age > 30 ? Math.min((prefs.age - 30) * 5, 250) : 0;
25	  const factor = ACTIVITY_FACTOR[prefs.activityLevel];
26	  let calories = Math.round((base - ageDelta) * factor);
27	
28	  // Weight-loss goal trims another 250 kcal/day, with a 1200 floor.
29	  if (prefs.goals.includes('weight-loss')) calories = Math.max(1200, calories - 250);
30	
31	  const proteinGrams = Math.round((calories * 0.30) / 4);
32	  // Low-sodium goal lowers the cap from the default 2300 mg to 1500 mg.
33	  const sodiumMg = prefs.goals.includes('low-sodium') ? 1500 : 2300;
34	  const addedSugarGrams = Math.round((calories * 0.10) / 4);
35	
36	  return { calories, proteinGrams, sodiumMg, addedSugarGrams };
37	}
