1	import type { Question, QuestionType } from '@domain/questions/question';
2	
3	/** Every question type the scoring pipeline knows how to handle. */
4	export const ALL_QUESTION_TYPES: readonly QuestionType[] = [
5	  'single_choice', 'multi_choice', 'numeric', 'text', 'true_false', 'fill_in_blank'
6	];
7	
8	/**
9	 * Validate that a weights map covers every question type. Throws on the
10	 * first missing key — used by the business config loader to fail fast
11	 * rather than relying on silent fallbacks downstream.
12	 */
13	export function validateWeights(weights: Record<string, number>): void {
14	  for (const t of ALL_QUESTION_TYPES) {
15	    if (typeof weights[t] !== 'number' || !Number.isFinite(weights[t])) {
16	      throw new Error(`Missing or invalid weight for question type '${t}'`);
17	    }
18	  }
19	}
20	
21	export interface AttemptAnswer {
22	  questionId: string;
23	  selectedChoiceIds?: string[];
24	  numericAnswer?: number;
25	  textAnswer?: string;
26	  fillAnswer?: string;
27	}
28	
29	function normalize(s: string, caseSensitive: boolean): string {
30	  const trimmed = s.trim();
31	  return caseSensitive ? trimmed : trimmed.toLowerCase();
32	}
33	
34	export interface AutoScoreResult {
35	  questionId: string;
36	  rawScore: number;        // 0..maxScore
37	  isCorrect: boolean;
