41	export function autoScore(question: Question, answer: AttemptAnswer): AutoScoreResult {
42	  const max = question.maxScore;
43	  switch (question.type) {
44	    case 'single_choice':
45	    case 'true_false': {
46	      const selected = answer.selectedChoiceIds ?? [];
47	      const correct = selected.length === 1 && question.correctChoiceIds.includes(selected[0]);
48	      return { questionId: question.id, rawScore: correct ? max : 0, isCorrect: correct, manualReviewRequired: false };
49	    }
50	    case 'fill_in_blank': {
51	      const supplied = answer.fillAnswer;
52	      if (typeof supplied !== 'string' || supplied.trim().length === 0) {
53	        return { questionId: question.id, rawScore: 0, isCorrect: false, manualReviewRequired: false };
54	      }
55	      const candidate = normalize(supplied, question.caseSensitive);
56	      const accepted = question.acceptedAnswers.map((a) => normalize(a, question.caseSensitive));
57	      const hit = accepted.includes(candidate);
58	      return { questionId: question.id, rawScore: hit ? max : 0, isCorrect: hit, manualReviewRequired: false };
59	    }
60	    case 'multi_choice': {
61	      const selected = new Set(answer.selectedChoiceIds ?? []);
62	      const correct = new Set(question.correctChoiceIds);
63	      // Partial credit: fraction of correct picked minus penalty for wrong picks, clamped.
64	      let hits = 0; let wrong = 0;
65	      for (const id of selected) (correct.has(id) ? hits++ : wrong++);
66	      const total = correct.size;
67	      const ratio = Math.max(0, (hits - wrong) / total);
68	      const raw = roundToIncrement(ratio * max, 0.5);
69	      return { questionId: question.id, rawScore: raw, isCorrect: hits === total && wrong === 0, manualReviewRequired: false };
70	    }
71	    case 'numeric': {
72	      const val = answer.numericAnswer;
73	      if (val === undefined || val === null || !Number.isFinite(val) || question.correctNumeric === null) {
74	        return { questionId: question.id, rawScore: 0, isCorrect: false, manualReviewRequired: false };
75	      }
76	      const within = Math.abs(val - question.correctNumeric) <= question.numericTolerance;
77	      return { questionId: question.id, rawScore: within ? max : 0, isCorrect: within, manualReviewRequired: false };
