76	    templateId: input.templateId ?? null,
77	    subject: renderTemplate(subject, vars),
78	    body: renderTemplate(body, vars),
79	    variables: vars,
80	    attempts: 0,
81	    status: 'pending',
82	    lastError: null,
83	    createdAt: Date.now(),
84	    nextAttemptAt: Date.now(),
85	    deliveredAt: null,
86	    readAt: null
