94	async function processOne(messageId: string): Promise<void> {
95	  const cfg = businessConfig();
96	  const message = await messagesRepository.get(messageId);
97	  if (!message) return;
98	  if (message.status !== 'pending') return;
99	  if (message.nextAttemptAt > Date.now()) return;
100	
101	  const now = new Date();
102	  const attempts = message.attempts + 1;
103	
104	  // 1. Subscription drop check
105	  const prefs: SubscriptionPreferences = await messagesRepository.getSubscription(message.toUserId);
106	  if (prefs.unsubscribed.includes(message.category)) {
107	    const dropped: Message = { ...message, attempts, status: 'dead', lastError: `Recipient unsubscribed from ${message.category}` };
108	    await messagesRepository.put(dropped);
109	    await messagesRepository.pushDeadLetter(dropped);
110	    logger.warn('messaging.dropped', { messageId: message.id, reason: dropped.lastError });
111	    return;
112	  }
113	
114	  // 2. Max attempts → dead letter
115	  if (attempts > cfg.messaging.maxAttempts) {
116	    const dead: Message = { ...message, attempts, status: 'dead', lastError: `Exceeded ${cfg.messaging.maxAttempts} attempts` };
117	    await messagesRepository.put(dead);
118	    await messagesRepository.pushDeadLetter(dead);
119	    logger.warn('messaging.dead_letter', { messageId: message.id, reason: dead.lastError });
120	    return;
121	  }
122	
123	  // 3. Quiet hours — per-user preference stored in localStorage; falls back
124	  // to the global default from business config when not set.
125	  const recipientQuiet: QuietHours | null = preferences.getQuietHours(message.toUserId);
126	  const quiet = recipientQuiet ?? cfg.quietHours;
127	  if (isWithinQuietHours(now, quiet)) {
128	    const until = nextQuietEnd(now, quiet).getTime();
129	    const deferred: Message = {
130	      ...message,
131	      attempts,
132	      nextAttemptAt: Math.max(until, backoffNextAttempt(now, attempts, cfg.messaging.retryBackoffMs)),
133	      lastError: 'Quiet hours'
134	    };
135	    await messagesRepository.put(deferred);
136	    logger.info('messaging.deferred', {
137	      messageId: message.id, attempts, reason: 'Quiet hours', nextAttemptAt: deferred.nextAttemptAt
138	    });
139	    return;
140	  }
141	
142	  // 4. Rate limit (atomic, IDB-backed)
143	  const consume = await messagingPolicyRepository.tryConsumeRate(
144	    message.toUserId,
145	    cfg.messaging.ratePerMinute,
146	    now.getTime()
147	  );
148	  if (!consume.ok) {
149	    const deferred: Message = {
150	      ...message,
151	      attempts,
152	      nextAttemptAt: Math.max(consume.nextAvailableAt, backoffNextAttempt(now, attempts, cfg.messaging.retryBackoffMs)),
153	      lastError: 'Rate limit'
154	    };
155	    await messagesRepository.put(deferred);
156	    logger.info('messaging.deferred', {
157	      messageId: message.id, attempts, reason: 'Rate limit', nextAttemptAt: deferred.nextAttemptAt
158	    });
159	    return;
160	  }
161	
162	  // 5. Deliver
163	  const delivered: Message = { ...message, attempts, status: 'delivered', deliveredAt: now.getTime() };
164	  await messagesRepository.put(delivered);
165	  logger.info('messaging.delivered', { messageId: message.id, attempts });
166	}
