15	export async function loadHealthProfile(): Promise<void> {
16	  const userId = requireSession();
17	  const record = await healthRepository.get(userId);
18	  if (!record || !record.encryptedPreferences) {
19	    profileStore.set({ preferences: EMPTY_PREFS, loaded: true });
20	    return;
