22	  const key = currentEncryptionKey();
23	  if (!key) throw new Error('No encryption key in session');
24	  if (!isEncrypted(record.encryptedPreferences)) {
25	    profileStore.set({ preferences: EMPTY_PREFS, loaded: true });
26	    return;
