32	export async function saveHealthProfile(prefs: DietaryPreferences): Promise<void> {
33	  const userId = requireSession();
34	  const key = currentEncryptionKey();
35	  if (!key) throw new Error('No encryption key in session');
36	  const encryptedPreferences = await encryptString(key, JSON.stringify(prefs));
37	  const record: HealthProfile = { id: userId, userId, encryptedPreferences, updatedAt: Date.now() };
