56	/**
57	 * Apply a one-click swap and persist it. The original food id is added to
58	 * the user's `dislikes` list so future recommendations skip it; the swap
59	 * target is now the canonical recommendation. Throws when no equivalent is
60	 * configured for `originalFoodId`.
61	 */
62	export async function applySwap(originalFoodId: string): Promise<{ swap: FoodItem; preferences: DietaryPreferences }> {
63	  const swap = swapEquivalent(originalFoodId);
64	  if (!swap) throw new Error(`No equivalent configured for ${originalFoodId}`);
65	  // Read the current preferences from the in-memory store; fall back to empty.
66	  const current = (await new Promise<DietaryPreferences>((resolve) => {
67	    const off = profileStore.subscribe((v) => resolve(v.preferences));
68	    off();
69	  }));
70	  const next: DietaryPreferences = {
71	    ...current,
72	    dislikes: current.dislikes.includes(originalFoodId)
73	      ? current.dislikes
74	      : [...current.dislikes, originalFoodId]
75	  };
76	  await saveHealthProfile(next);
77	  return { swap, preferences: next };
78	}
