1	import type { AttemptAnswer } from '@domain/grading/scoring';
2	import { idbAll, idbGet, idbPut } from './indexedDb';
3	
4	export interface Attempt {
5	  id: string;
6	  userId: string;
7	  questionId: string;
8	  answer: AttemptAnswer;
9	  autoScore: number | null;       // null when needs manual grading
10	  isCorrect: boolean | null;
11	  needsManualGrading: boolean;
12	  submittedAt: number;
13	}
14	
15	export const attemptsRepository = {
16	  list: (): Promise<Attempt[]> => idbAll<Attempt>('attempts'),
17	  get: (id: string): Promise<Attempt | undefined> => idbGet<Attempt>('attempts', id),
18	  put: (a: Attempt): Promise<void> => idbPut('attempts', a)
