1	<script lang="ts">
2	  import { onMount } from 'svelte';
3	  import PageHeader from '../components/PageHeader.svelte';
4	  import RouteGuard from '../components/RouteGuard.svelte';
5	  import { listAttempts } from '@application/services/attemptService';
6	  import {
7	    listGrades, submitFirstReview, submitSecondReview,
8	    decryptNotes, isComplete, NotesDecryptionError
9	  } from '@application/services/gradingService';
10	  import { questionsRepository } from '@persistence/questionsRepository';
11	  import type { Attempt } from '@persistence/attemptsRepository';
12	  import type { Grade } from '@persistence/gradesRepository';
13	  import type { Question } from '@domain/questions/question';
14	  import { businessConfig } from '@application/services/businessConfig';
15	  import { requiresSecondReview } from '@domain/grading/scoring';
16	
17	  const cfg = businessConfig().grading;
18	
19	  let attempts: Attempt[] = [];
20	  let grades: Grade[] = [];
21	  let questionsById: Record<string, Question> = {};
22	  let working: { attempt: Attempt; grade: Grade | null; question: Question } | null = null;
23	  let scoreInput = 0;
24	  let notesInput = '';
25	  let decryptedNotes = '';
26	  let notesUnreadable = false;
27	  let error = '';
28	
29	  async function reload(): Promise<void> {
30	    attempts = await listAttempts();
31	    grades = await listGrades();
32	    const qs = await questionsRepository.list();
33	    questionsById = Object.fromEntries(qs.map((q) => [q.id, q]));
34	  }
35	
36	  onMount(reload);
37	
38	  function gradeFor(attemptId: string): Grade | null {
39	    return grades.find((g) => g.attemptId === attemptId) ?? null;
40	  }
41	
42	  async function open(attempt: Attempt): Promise<void> {
43	    error = '';
44	    decryptedNotes = '';
45	    notesUnreadable = false;
46	    const question = questionsById[attempt.questionId];
47	    if (!question) return;
48	    const grade = gradeFor(attempt.id);
49	    working = { attempt, grade, question };
50	    scoreInput = grade?.firstScore ?? 0;
51	    notesInput = '';
52	    if (grade?.notesEncrypted) {
53	      try {
54	        decryptedNotes = await decryptNotes(grade.notesEncrypted);
55	      } catch (e) {
56	        if (e instanceof NotesDecryptionError) {
57	          notesUnreadable = true;
58	        } else {
59	          error = e instanceof Error ? e.message : 'Failed to load notes';
60	        }
61	      }
62	    }
63	  }
64	
65	  async function submitFirst(): Promise<void> {
66	    if (!working) return;
67	    error = '';
68	    try {
69	      await submitFirstReview({ attemptId: working.attempt.id, score: scoreInput, notes: notesInput });
70	      await reload();
71	      working = null;
72	    } catch (e) { error = e instanceof Error ? e.message : 'Failed'; }
73	  }
74	
75	  async function submitSecond(): Promise<void> {
76	    if (!working || !working.grade) return;
77	    error = '';
78	    try {
79	      await submitSecondReview(working.grade.id, { score: scoreInput, notes: notesInput });
80	      await reload();
81	      working = null;
82	    } catch (e) {
83	      error = e instanceof Error ? e.message : 'Failed';
84	      await reload();
85	    }
86	  }
87	
88	  $: deltaTriggers = working && working.grade
89	    ? requiresSecondReview(working.grade.firstScore, scoreInput, cfg.secondReviewDelta)
90	    : false;
91	</script>
92	
93	<RouteGuard route="review">
94	  <PageHeader
95	    title="Reviewer · Grading"
96	    subtitle={`Manual scoring on the ${cfg.partialIncrement} grid; the second review finalizes the grade as the type-weighted average.`}
97	  />
98	
99	  <div class="card">
100	    <table style="width:100%; font-size:13px;">
101	      <thead><tr><th>Attempt</th><th>Question</th><th>Auto</th><th>Manual</th><th>Final</th><th>Status</th><th></th></tr></thead>
102	      <tbody>
103	        {#each attempts as a (a.id)}
104	          {@const g = gradeFor(a.id)}
105	          {@const q = questionsById[a.questionId]}
106	          <tr>
107	            <td>{a.id.slice(0, 12)}…</td>
108	            <td>{q?.prompt ?? '—'}</td>
109	            <td>{a.autoScore ?? '—'}</td>
110	            <td>{g?.firstScore ?? '—'}{g?.secondScore !== null && g?.secondScore !== undefined ? ` / ${g.secondScore}` : ''}</td>
111	            <td>{g?.finalScore ?? '—'}</td>
112	            <td>
113	              {#if g && isComplete(g) && g.secondScore !== null}
114	                graded (2 reviewers){#if g.blockedReason}<span style="color:#f1c40f;" title={g.blockedReason}> · audit</span>{/if}
115	              {:else if g && isComplete(g)}
116	                graded (1 reviewer)
117	              {:else if a.needsManualGrading}
118	                needs grading
119	              {:else}
120	                auto
121	              {/if}
122	            </td>
123	            <td>
124	              {#if a.needsManualGrading && !g}
125	                <button class="btn secondary" on:click={() => open(a)}>Grade</button>
126	              {:else if g && g.secondScore === null}
127	                <button class="btn secondary" on:click={() => open(a)}>2nd review</button>
128	              {:else if g}
129	                <button class="btn secondary" on:click={() => open(a)}>View</button>
130	              {/if}
131	            </td>
132	          </tr>
133	        {/each}
134	      </tbody>
135	    </table>
136	  </div>
137	</RouteGuard>
138	
139	{#if working}
140	  <div class="card" style="position:fixed; right:24px; bottom:24px; width:min(440px, 92vw); z-index:60;">
141	    <h3 style="margin-top:0;">Grade attempt</h3>
142	    <p style="color:var(--muted);">{working.question.prompt}</p>
143	    <p>Max score: {working.question.maxScore} · Type weight: {cfg.weights[working.question.type]}</p>
144	
145	    {#if working.grade}
146	      <p>First score: <strong>{working.grade.firstScore}</strong>
147	      {#if working.grade.secondScore !== null} · Second score: <strong>{working.grade.secondScore}</strong>{/if}</p>
148	      {#if working.grade.blockedReason}
149	        <p style="color:#ff7676;">{working.grade.blockedReason}</p>
150	      {/if}
151	    {/if}
152	
153	    <label>Score (step {cfg.partialIncrement})<br/>
154	      <input type="number" step={cfg.partialIncrement} min="0" max={working.question.maxScore} bind:value={scoreInput} />
155	    </label><br/><br/>
156	    <label>Notes (encrypted at rest)<br/>
157	      <textarea rows="3" bind:value={notesInput} style="width:100%"></textarea>
158	    </label>
159	
160	    {#if notesUnreadable}
161	      <p style="color:var(--muted); font-size:12px; font-style: italic;">[Existing notes were encrypted by a different reviewer and cannot be decrypted in your session.]</p>
162	    {:else if decryptedNotes}
163	      <p style="color:var(--muted); font-size:12px;">Existing notes: {decryptedNotes}</p>
164	    {/if}
165	
166	    {#if deltaTriggers}
167	      <p style="color:#f1c40f;">Delta exceeds {cfg.secondReviewDelta} — flagged for audit; the second review will still finalize the grade.</p>
168	    {/if}
169	
170	    {#if error}<p style="color:#ff7676;">{error}</p>{/if}
171	
172	    <div style="display:flex; gap:8px; justify-content:flex-end; margin-top:12px;">
173	      <button class="btn secondary" on:click={() => (working = null)}>Close</button>
174	      {#if working.grade && working.grade.secondScore === null}
175	        <button class="btn" on:click={submitSecond}>Submit second review</button>
176	      {:else if !working.grade}
177	        <button class="btn" on:click={submitFirst}>Submit first review</button>
178	      {/if}
179	    </div>
180	  </div>
181	{/if}
