1	/** Per-store record schema validators used during snapshot import. */
2	
3	type Validator = (item: unknown) => string | null;
4	
5	function isObject(v: unknown): v is Record<string, unknown> {
6	  return v !== null && typeof v === 'object' && !Array.isArray(v);
7	}
8	
9	function requireString(o: Record<string, unknown>, key: string): string | null {
10	  return typeof o[key] === 'string' && (o[key] as string).length > 0 ? null : `${key} must be a non-empty string`;
11	}
12	
13	function requireNumber(o: Record<string, unknown>, key: string): string | null {
14	  return typeof o[key] === 'number' && Number.isFinite(o[key] as number) ? null : `${key} must be a finite number`;
15	}
16	
17	function requireBoolean(o: Record<string, unknown>, key: string): string | null {
18	  return typeof o[key] === 'boolean' ? null : `${key} must be a boolean`;
19	}
20	
21	function requireArray(o: Record<string, unknown>, key: string): string | null {
22	  return Array.isArray(o[key]) ? null : `${key} must be an array`;
23	}
24	
25	function checkAll(...errors: (string | null)[]): string | null {
26	  for (const e of errors) if (e) return e;
27	  return null;
28	}
29	
30	const ALLOWED_QUESTION_TYPES = new Set(['single_choice','multi_choice','numeric','text','true_false','fill_in_blank']);
31	const ALLOWED_QUESTION_STATUS = new Set(['active','inactive','deleted']);
32	
33	const questionValidator: Validator = (item) => {
34	  if (!isObject(item)) return 'Not an object';
35	  const e = checkAll(
36	    requireString(item, 'id'),
37	    requireString(item, 'prompt'),
38	    requireNumber(item, 'difficulty'),
39	    requireNumber(item, 'maxScore'),
40	    requireArray(item, 'choices'),
41	    requireArray(item, 'correctChoiceIds'),
42	    requireArray(item, 'tags'),
43	    requireArray(item, 'knowledgePoints'),
44	    requireArray(item, 'applicableDepartments')
45	  );
46	  if (e) return e;
47	  if (typeof item.type !== 'string' || !ALLOWED_QUESTION_TYPES.has(item.type)) return 'Invalid question type';
48	  if (typeof item.status !== 'string' || !ALLOWED_QUESTION_STATUS.has(item.status)) return 'Invalid status';
49	  return null;
50	};
51	
52	const attemptValidator: Validator = (item) => {
53	  if (!isObject(item)) return 'Not an object';
54	  return checkAll(
55	    requireString(item, 'id'),
56	    requireString(item, 'userId'),
57	    requireString(item, 'questionId'),
58	    requireBoolean(item, 'needsManualGrading'),
59	    requireNumber(item, 'submittedAt')
60	  );
61	};
62	
63	const gradeValidator: Validator = (item) => {
64	  if (!isObject(item)) return 'Not an object';
65	  const e = checkAll(
66	    requireString(item, 'id'),
67	    requireString(item, 'attemptId'),
68	    requireString(item, 'questionId'),
69	    requireString(item, 'graderId'),
70	    requireNumber(item, 'firstScore'),
71	    requireBoolean(item, 'awaitingSecondReview'),
72	    requireNumber(item, 'createdAt'),
73	    requireNumber(item, 'updatedAt')
74	  );
75	  if (e) return e;
76	  if (item.finalScore !== null && typeof item.finalScore !== 'number') return 'finalScore must be number or null';
77	  return null;
78	};
79	
80	const messageValidator: Validator = (item) => {
81	  if (!isObject(item)) return 'Not an object';
82	  const e = checkAll(
83	    requireString(item, 'id'),
84	    requireString(item, 'fromUserId'),
85	    requireString(item, 'toUserId'),
86	    requireString(item, 'category'),
87	    requireNumber(item, 'attempts'),
88	    requireString(item, 'status'),
89	    requireNumber(item, 'createdAt')
90	  );
91	  return e;
92	};
93	
94	const healthProfileValidator: Validator = (item) => {
95	  if (!isObject(item)) return 'Not an object';
96	  return checkAll(
97	    requireString(item, 'id'),
98	    requireString(item, 'userId'),
99	    requireNumber(item, 'updatedAt')
100	  );
101	};
102	
103	const ALLOWED_SAMPLE_TYPES_SET = new Set(['blood','tissue','serum','saliva','plasma','urine']);
104	
105	const catalogValidator: Validator = (item) => {
106	  if (!isObject(item)) return 'Not an object';
107	  if (typeof item.id !== 'string' || item.id.length === 0) return 'id must be non-empty string';
108	  // Catalog envelopes can be config records (id starts with cfgrec:), seed flags, or
109	  // subscription envelopes. Only validate config records strictly.
110	  if (item.id.startsWith('cfgrec:')) {
111	    if (!isObject(item.record)) return 'record missing';
112	    const r = item.record as Record<string, unknown>;
113	    const e = checkAll(
114	      requireString(r, 'id'),
115	      requireString(r, 'name'),
116	      requireString(r, 'device'),
117	      requireString(r, 'department'),
118	      requireString(r, 'project'),
119	      requireString(r, 'sampleQueue'),
120	      requireString(r, 'sampleType'),
121	      requireString(r, 'effectiveFrom'),
122	      requireString(r, 'effectiveTo'),
123	      requireNumber(r, 'priceUsd'),
124	      requireBoolean(r, 'valid'),
125	      requireArray(r, 'tags')
126	    );
127	    if (e) return `record.${e}`;
128	    if (!ALLOWED_SAMPLE_TYPES_SET.has(r.sampleType as string)) return `record.sampleType invalid`;
129	  }
130	  return null;
131	};
132	
133	const tripValidator: Validator = (item) => {
134	  if (!isObject(item)) return 'Not an object';
135	  return checkAll(
136	    requireString(item, 'id'),
137	    requireString(item, 'name'),
138	    requireString(item, 'origin'),
139	    requireString(item, 'destination'),
140	    requireNumber(item, 'departureAt'),
141	    requireNumber(item, 'rows'),
142	    requireNumber(item, 'cols'),
143	    requireString(item, 'createdBy'),
144	    requireNumber(item, 'createdAt')
145	  );
146	};
147	
148	const ALLOWED_SEAT_KIND = new Set(['standard', 'ada', 'crew']);
149	
150	const seatValidator: Validator = (item) => {
151	  if (!isObject(item)) return 'Not an object';
152	  const e = checkAll(
153	    requireString(item, 'id'),
154	    requireString(item, 'tripId'),
155	    requireString(item, 'seatId'),
156	    requireString(item, 'label'),
157	    requireNumber(item, 'row'),
158	    requireNumber(item, 'column')
159	  );
160	  if (e) return e;
161	  if (typeof item.kind !== 'string' || !ALLOWED_SEAT_KIND.has(item.kind)) return 'kind must be standard|ada|crew';
162	  return null;
163	};
164	
165	const holdValidator: Validator = (item) => {
166	  if (!isObject(item)) return 'Not an object';
167	  return checkAll(
168	    requireString(item, 'id'),
169	    requireString(item, 'tripId'),
170	    requireString(item, 'seatId'),
171	    requireString(item, 'ownerTabId'),
172	    requireNumber(item, 'expiresAt')
173	  );
174	};
175	
176	const bookingValidator: Validator = (item) => {
177	  if (!isObject(item)) return 'Not an object';
178	  return checkAll(
179	    requireString(item, 'id'),
180	    requireString(item, 'tripId'),
181	    requireString(item, 'seatId'),
182	    requireNumber(item, 'bookedAt')
183	  );
184	};
185	
186	const deadLetterValidator: Validator = messageValidator;
187	
188	export const STORE_VALIDATORS: Record<string, Validator> = {
189	  questions: questionValidator,
190	  attempts: attemptValidator,
191	  grades: gradeValidator,
192	  messages: messageValidator,
193	  deadLetters: deadLetterValidator,
194	  healthProfiles: healthProfileValidator,
195	  catalogs: catalogValidator,
196	  trips: tripValidator,
197	  seats: seatValidator,
198	  holds: holdValidator,
199	  bookings: bookingValidator
200	};
