2	import { calculateNutritionBudget } from '@domain/health/nutrition';
3	import type { DietaryPreferences } from '@domain/health/healthProfile';
4	
5	function prefs(over: Partial<DietaryPreferences> = {}): DietaryPreferences {
6	  return { goals: [], allergens: [], dislikes: [], age: 30, activityLevel: 'moderate', ...over };
7	}
8	
9	describe('calculateNutritionBudget', () => {
10	  it('returns null when age or activity is missing', () => {
11	    expect(calculateNutritionBudget(prefs({ age: null }))).toBeNull();
12	    expect(calculateNutritionBudget(prefs({ activityLevel: null }))).toBeNull();
13	  });
14	
15	  it('rejects nonsensical ages', () => {
16	    expect(calculateNutritionBudget(prefs({ age: 0 }))).toBeNull();
17	    expect(calculateNutritionBudget(prefs({ age: 121 }))).toBeNull();
18	    expect(calculateNutritionBudget(prefs({ age: NaN }))).toBeNull();
19	  });
20	
21	  it('is deterministic for the same inputs', () => {
22	    const a = calculateNutritionBudget(prefs());
23	    const b = calculateNutritionBudget(prefs());
24	    expect(a).toEqual(b);
25	  });
26	
27	  it('produces base budget for a 30 year-old at moderate activity', () => {
28	    const b = calculateNutritionBudget(prefs())!;
29	    expect(b.calories).toBe(2000);
30	    expect(b.proteinGrams).toBe(150); // 30% of 2000 / 4
31	    expect(b.sodiumMg).toBe(2300);
32	    expect(b.addedSugarGrams).toBe(50); // 10% of 2000 / 4
33	  });
