134	  const prefs: SubscriptionPreferences = await messagesRepository.getSubscription(message.toUserId);
135	  if (prefs.unsubscribed.includes(message.category)) {
136	    const dropped: Message = { ...message, attempts, status: 'dead', lastError: `Recipient unsubscribed from ${message.category}` };
137	    await messagesRepository.put(dropped);
138	    await messagesRepository.pushDeadLetter(dropped);
139	    logger.warn('messaging.dropped', { messageId: message.id, reason: dropped.lastError });
140	    return;
141	  }
142	
143	  // 2. Max attempts → dead letter
144	  if (attempts > cfg.messaging.maxAttempts) {
145	    const dead: Message = { ...message, attempts, status: 'dead', lastError: `Exceeded ${cfg.messaging.maxAttempts} attempts` };
146	    await messagesRepository.put(dead);
147	    await messagesRepository.pushDeadLetter(dead);
148	    logger.warn('messaging.dead_letter', { messageId: message.id, reason: dead.lastError });
149	    return;
150	  }
151	
152	  // 3. Quiet hours — per-user preference stored in localStorage; falls back
153	  // to the global default from business config when not set.
154	  const recipientQuiet: QuietHours | null = preferences.getQuietHours(message.toUserId);
155	  const quiet = recipientQuiet ?? cfg.quietHours;
156	  if (isWithinQuietHours(now, quiet)) {
157	    const until = nextQuietEnd(now, quiet).getTime();
158	    const deferred: Message = {
159	      ...message,
160	      attempts,
161	      nextAttemptAt: Math.max(until, backoffNextAttempt(now, attempts, cfg.messaging.retryBackoffMs)),
162	      lastError: 'Quiet hours'
163	    };
164	    await messagesRepository.put(deferred);
165	    logger.info('messaging.deferred', {
166	      messageId: message.id, attempts, reason: 'Quiet hours', nextAttemptAt: deferred.nextAttemptAt
167	    });
168	    return;
169	  }
170	
171	  // 4. Rate limit (atomic, IDB-backed)
172	  const consume = await messagingPolicyRepository.tryConsumeRate(
173	    message.toUserId,
174	    cfg.messaging.ratePerMinute,
175	    now.getTime()
176	  );
177	  if (!consume.ok) {
178	    const deferred: Message = {
179	      ...message,
180	      attempts,
181	      nextAttemptAt: Math.max(consume.nextAvailableAt, backoffNextAttempt(now, attempts, cfg.messaging.retryBackoffMs)),
182	      lastError: 'Rate limit'
183	    };
184	    await messagesRepository.put(deferred);
185	    logger.info('messaging.deferred', {
186	      messageId: message.id, attempts, reason: 'Rate limit', nextAttemptAt: deferred.nextAttemptAt
187	    });
188	    return;
189	  }
190	
191	  // 5. Deliver
192	  const delivered: Message = { ...message, attempts, status: 'delivered', deliveredAt: now.getTime() };
193	  await messagesRepository.put(delivered);
194	  logger.info('messaging.delivered', { messageId: message.id, attempts });
