        userId,
        department: dept,
        questionId: question.id,
        applicableDepartments: question.applicableDepartments
      });
      throw new AuthorizationError(
        `Question is restricted to departments [${question.applicableDepartments.join(', ')}]`
      );
    }
  }
"}

