      attempts,
      nextAttemptAt: Math.max(consume.nextAvailableAt, backoffNextAttempt(now, attempts, cfg.messaging.retryBackoffMs)),
      lastError: 'Rate limit'
    };
    await messagesRepository.put(deferred);
    logger.info('messaging.deferred', {
      messageId: message.id, attempts, reason: 'Rate limit', nextAttemptAt: deferred.nextAttemptAt
    });
