  --warning: #f1c40f;
  --success: #4ad48b;
  --border: #232732;
  --border-strong: #303747;
  --focus-ring: 0 0 0 2px rgba(79, 140, 255, 0.45);
  --shadow-card: 0 1px 2px rgba(0,0,0,0.25), 0 1px 1px rgba(0,0,0,0.18);
