  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}
* { box-sizing: border-box; }
html, body {
  margin: 0; padding: 0; background: var(--bg); color: var(--fg);
  min-height: 100vh;
  letter-spacing: -0.005em;
}

/* ----------------------------------------------------------------------
   Typographic hierarchy. The previous baseline relied on the browser's
   default heading sizes, which collapsed visual hierarchy in dense
   workspace pages. The scale below is a 1.25 modular scale anchored at
   14px body, with weights and tracking tuned for the dark surface.
   ---------------------------------------------------------------------- */
h1, h2, h3, h4, h5, h6 {
  color: var(--fg-strong);
  font-weight: 600;
  line-height: 1.25;
  margin: 0 0 0.5em;
  letter-spacing: -0.015em;
}
h1 { font-size: 1.875rem; font-weight: 700; letter-spacing: -0.02em; }
h2 { font-size: 1.5rem;   font-weight: 650; }
h3 { font-size: 1.175rem; font-weight: 600; }
h4 { font-size: 1rem;     font-weight: 600; text-transform: uppercase; letter-spacing: 0.04em; color: var(--muted-strong); }
small, .text-muted { color: var(--muted); font-size: 0.8125rem; }
strong { color: var(--fg-strong); font-weight: 600; }
code, kbd, samp { font-family: "JetBrains Mono", ui-monospace, "SF Mono", Menlo, Consolas, monospace; font-size: 0.85em; }

a {
  color: var(--accent);
  text-decoration: none;
  transition: color var(--transition);
}
a:hover { color: var(--accent-hover); text-decoration: underline; text-underline-offset: 3px; }
a:focus-visible { outline: none; box-shadow: var(--focus-ring); border-radius: 2px; }

button { font: inherit; cursor: pointer; }

/* Form controls — uniform interaction affordances. */
input, select, textarea {
  background: var(--panel-elevated);
  color: var(--fg);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  padding: 8px 10px;
  font: inherit;
  transition: border-color var(--transition), box-shadow var(--transition), background var(--transition);
}
input:hover, select:hover, textarea:hover { border-color: var(--border-strong); }
input:focus, select:focus, textarea:focus {
  outline: none;
  border-color: var(--accent);
  box-shadow: var(--focus-ring);
}
input:disabled, select:disabled, textarea:disabled { opacity: 0.55; cursor: not-allowed; }

/* ----------------------------------------------------------------------
   App shell — unchanged geometry, refined separators and hover affordances.
   ---------------------------------------------------------------------- */
.app-shell {
  display: grid;
  grid-template-columns: 240px 1fr;
  grid-template-rows: 56px 1fr;
  grid-template-areas: "brand topbar" "nav main";
  min-height: 100vh;
}
.brand {
  grid-area: brand;
  display: flex; align-items: center; padding: 0 18px;
  border-bottom: 1px solid var(--border);
  border-right: 1px solid var(--border);
  font-weight: 700; font-size: 0.95rem;
  letter-spacing: -0.01em; color: var(--fg-strong);
}
.topbar {
  grid-area: topbar;
  display: flex; align-items: center; padding: 0 18px;
  border-bottom: 1px solid var(--border);
  color: var(--muted);
  font-size: 0.8125rem;
}
.nav { grid-area: nav; padding: 14px 12px; border-right: 1px solid var(--border); display: flex; flex-direction: column; gap: 2px; }
.nav a {
  padding: 9px 12px;
  border-radius: var(--radius-sm);
  color: var(--muted-strong);
  font-weight: 500;
  font-size: 0.8875rem;
  transition: background var(--transition), color var(--transition);
  position: relative;
}
.nav a:hover { background: var(--panel); color: var(--fg-strong); text-decoration: none; }
.nav a.active {
  background: var(--accent-soft);
  color: var(--fg-strong);
  font-weight: 600;
}
.nav a.active::before {
  content: "";
  position: absolute; left: 0; top: 25%; bottom: 25%;
  width: 3px; border-radius: 0 3px 3px 0;
  background: var(--accent);
}
.main { grid-area: main; padding: 28px 32px; overflow: auto; }

@media (max-width: 800px) {
  .app-shell { grid-template-columns: 1fr; grid-template-rows: 56px auto 1fr; grid-template-areas: "brand" "nav" "main"; }
  .brand { border-right: none; }
  .nav { flex-direction: row; flex-wrap: wrap; border-right: none; border-bottom: 1px solid var(--border); }
  .nav a.active::before { display: none; }
  .main { padding: 18px; }
}

.modal-backdrop {
  position: fixed; inset: 0;
  background: rgba(8, 10, 14, 0.62);
  backdrop-filter: blur(2px);
  display: flex; align-items: center; justify-content: center; z-index: 50;
  animation: fade-in var(--transition);
}
.modal {
  background: var(--panel);
  border: 1px solid var(--border-strong);
  border-radius: var(--radius-lg);
  padding: 22px 24px;
  width: min(560px, 92vw);
  max-height: 86vh;
  overflow: auto;
  box-shadow: var(--shadow-elevated);
  animation: pop-in var(--transition);
}
.modal header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 14px; }
.modal header button { background: transparent; border: none; color: var(--muted); font-size: 18px; padding: 4px 8px; border-radius: var(--radius-sm); transition: background var(--transition), color var(--transition); }
.modal header button:hover { background: var(--panel-elevated); color: var(--fg-strong); }

.card {
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: var(--radius-md);
  padding: 18px 20px;
  margin-bottom: 14px;
  box-shadow: var(--shadow-card);
}

/* ----------------------------------------------------------------------
   Buttons — clearer hover/active/focus affordances and a disabled state.
   ---------------------------------------------------------------------- */
.btn {
  background: var(--accent);
  color: white;
  border: 1px solid var(--accent);
  padding: 8px 16px;
  border-radius: var(--radius-sm);
  font-weight: 600;
  font-size: 0.875rem;
  letter-spacing: 0.005em;
  transition: background var(--transition), border-color var(--transition), transform var(--transition), box-shadow var(--transition), color var(--transition);
}
.btn:hover { background: var(--accent-hover); border-color: var(--accent-hover); }
.btn:active { background: var(--accent-active); border-color: var(--accent-active); transform: translateY(1px); }
.btn:focus-visible { outline: none; box-shadow: var(--focus-ring); }
.btn:disabled { background: var(--border); border-color: var(--border); color: var(--muted); cursor: not-allowed; transform: none; box-shadow: none; }

.btn.secondary {
  background: transparent;
  border: 1px solid var(--border-strong);
  color: var(--fg);
}
.btn.secondary:hover { background: var(--panel-elevated); border-color: var(--accent); color: var(--fg-strong); }
.btn.secondary:active { background: var(--panel); transform: translateY(1px); }
.btn.secondary:disabled { background: transparent; color: var(--muted); border-color: var(--border); }

/* Tables — gentle row hover and aligned numerics. */
table { border-collapse: collapse; width: 100%; }
th { text-align: left; font-weight: 600; color: var(--muted-strong); font-size: 0.75rem; text-transform: uppercase; letter-spacing: 0.06em; padding: 10px 12px; border-bottom: 1px solid var(--border-strong); }
td { padding: 10px 12px; border-bottom: 1px solid var(--border); }
tbody tr { transition: background var(--transition); }
tbody tr:hover { background: var(--panel-elevated); }

@keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
@keyframes pop-in {
  from { opacity: 0; transform: translateY(6px) scale(0.985); }
  to   { opacity: 1; transform: translateY(0)    scale(1); }
}

/* Respect reduced-motion preferences. */
@media (prefers-reduced-motion: reduce) {
  * { animation: none !important; transition: none !important; }
}"}

